class Solution {
    public String maximumBinaryString(String binary) {
        int n = binary.length();
        char[] chars = binary.toCharArray();
        int firstZero = -1;
        for (int i = 0; i < n; i++) {
            if (chars[i] == '0') {
                firstZero = i;
                break;
            }
        }
        if (firstZero == -1) return binary;
        for (int i = 0; i < n; i++) {
            if (i == firstZero) chars[i] = '0';
            else if (i < firstZero) chars[i] = '1';
            else chars[i] = '1';
        }
        return new String(chars);
    }
}
